var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐? 토토가 춤을 춘다고?","JPN":"は？　トトが踊るだって？","ENG":"What? Toto's gonna dance?","TWN":"什麼？是托托要跳喔？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"청각 기능에 이상이 생겼나? 방금 이상한 말을 들은 것 같은데?","JPN":"聴覚機能に異常が？　今変な言葉が聞こえた気が。","ENG":"Is there something wrong with my auditory function? I think I heard something weird.","TWN":"我的聽覺功能發生異常嗎？剛剛好像聽到什麼詭異的發言？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"쉬이. 토토. 괜찮아. 나 믿지?","JPN":"しーっ、トト。大丈夫だよ。私のこと、信じてるよね？","ENG":"Shh, Toto. It's all right. You believe in me, right?","TWN":"噓，托托，沒事的，你是相信我的吧？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"토토는 못 믿나 봐. 음성 데이터가 엄청 떨려.","JPN":"トトは信じてないみたい。音声データがぶるぶる震えてるよ。","ENG":"I don't think Toto does. His audio data shows that he's trembling.","TWN":"托托好像不相信你欸？它的聲音數據超抖的。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아, 아니야! 토토!","JPN":"ち、違うよ！　トト！","ENG":"N-no, he's not! Toto!","TWN":"才…才不是呢！托托！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"지금 막 심장이 뛰지 않아? 그건 네가 음악에 맞춰 춤출 준비가 됐다는 뜻이야!","JPN":"今心臓がバクバクしてない？　それは、あなたが音楽に合わせて踊る準備ができたってことなの！","ENG":"Can you feel your heart racing? That just means that you're ready to dance to the rhythm!","TWN":"現在心臟是不是怦怦跳？這就表示你已經準備好要隨著音樂起舞！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토, 우리 같이 언더그라운드를 돌던 거 기억나?","JPN":"トト、一緒にアンダーグラウンドを回ってたの覚えてる？","ENG":"Toto, remember when we wandered around in the Underground together?","TWN":"托托，你還記得我們一起在地下流浪的日子嗎？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"서로에 대해서도 잘 모르는 상태로 길을 헤매고, 공격당하고, 도망 다녔지.","JPN":"お互いのこともちゃんと知らないまま道に迷って、攻撃されて、逃げて回ったよね。","ENG":"We got lost, attacked, and even ran away together without really knowing each other.","TWN":"雖然那時我們對彼此都不熟悉，但我們一起迷路，一起被欺負，一起逃跑。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"널 어떻게 다뤄야 할 지도 몰라서 이리저리 끌려 다니고, 서로 힘들고, 괴로웠는데.","JPN":"あなたをどう扱えばいいのかもわからなくて、あちこち振り回されて、お互い苦労の連続で辛かったけど。","ENG":"I didn't know how to handle you, so I mostly got dragged around. And it was hard on us both.","TWN":"那時我也不知道該如何控制你，常常都被你拉著到處跑，搞得彼此都很累、很辛苦。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"누군가 날 공격하면 네가 몸을 던져 구해 주고, 난 맛있는 걸 찾아서 너에게 주고 그랬잖아.","JPN":"あなたは私が誰かに攻撃されると身を呈して守ってくれたし、私は美味しいものを探して食べさせてあげたりした。","ENG":"But when something attacked me, you protected me. And I found you tasty things to eat.","TWN":"但有人欺負我的話，你就會捨身救我，我找到好吃的，也都會跟你分享。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"말 없이도 우린 충분히 서로를 이해할 수 있었어.","JPN":"言葉なしでも、私たちは十分お互い理解できたの。","ENG":"We were able to understand each other without a word.","TWN":"我們之間的默契是不需要言語的。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……난 여전히 쟤가 저걸 들고 다니게 해도 괜찮은지 확신이 안 서.","JPN":"……私、今でもあの子があれを持ち歩いてもいいのか確信が持てないんだよね。","ENG":"You know, sometimes I still wonder if leaving that thing with her was a good idea in the first place.","TWN":"……我還是不確定讓她帶著那個東西，到底是好是壞。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"도로시. 쉿.","JPN":"ドロシー。しっ。","ENG":"Dorothy, shh!","TWN":"桃樂絲，噓。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"어떨 때는 한 번의 행동이 백마디 말보다 더 잘 통하기도 해. 우리처럼.","JPN":"一回の行動が百の言葉よりもっと通じ合えるときがある。私たちのように。","ENG":"Sometimes actions speak louder than words. Like you and me.","TWN":"有時候說一百句話，都比不上一個實際的行動來得有用，就像我們之間一樣。"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그러니까, 토토. 아까 허드슨 씨가 춤 췄던 거 기억해?","JPN":"だからね、トト。さっきのハドソンさんのダンス、覚えてる？","ENG":"So Toto, do you remember Mr. Hudson's last dance?","TWN":"托托，你記得剛剛哈德森跳的舞步吧？"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그 움직임을 따라하면 돼! 어려울 거 없어!","JPN":"その動きをマネすればいい！　難しくないよ！","ENG":"All you need to do is copy it! There's nothing hard about it!","TWN":"只要照著跳就好！一點也不難！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"이따가 체다 치즈를 얹은 감자 튀김도 사 줄게! 치즈 스틱도 추가해서!!","JPN":"後でチェダーチーズをのせたフライドポテトも買ってあげる！　チーズスティックも追加して！","ENG":"After this is all done, I'll buy you french fries with cheddar cheese on top! I'll add cheese sticks too!","TWN":"跳完後我買切達起司醬薯條給你！還加碼起司條！！"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"할 수 있지? 두근거리는 네 심장 소리를 들으면서……","JPN":"できるよね？　ワクワクしてるあなたの心臓の音を聞きながら……","ENG":"You think you can do that? Just listen to your heartbeat and...","TWN":"沒問題吧？隨著心臟的跳動聲……"},"stage":{"bg":"HAVEN","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"너를 보여줘, 토토!","JPN":"あなたを見せて、トト！","ENG":"Express yourself, Toto!","TWN":"展現你自己吧，托托！"},"stage":{"bg":"HAVEN","bgm":"BATTLE_SUMMER_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};